+/// IMPL-9a: maximum row count at which we still attempt to seed the
+/// per-table `QuotientFilter` via a one-shot scan. Tables above this
+/// threshold leave the filter in `too_large_to_build` state; consultation
+/// conservatively returns "maybe present" (no short-circuit) for them.
+///
+/// IMPL-9a wiring is currently scaffolding-only: the helpers are defined
+/// but not invoked from the direct-simple DELETE/UPDATE execution sites.
+/// A follow-up commit will wire consultation + INSERT/DELETE maintenance.
+#[allow(dead_code)]
+const QUOTIENT_FILTER_BUILD_ROW_CAP: usize = 10_000_000;
+
+/// IMPL-9a: per-table cached `QuotientFilter` bookkeeping used to
+/// short-circuit absent-rowid DELETE / UPDATE under the direct-simple
+/// fast path. See `Connection::quotient_filters`.
+#[derive(Debug)]
+#[allow(dead_code)]
+struct QuotientFilterEntry {
+    /// The underlying filter. Always allocated; geometry fixed at
+    /// construction (q=20, r=16, ~24 MiB).
+    filter: QuotientFilter,
+    /// `false` until the filter has been fully seeded from the live
+    /// B-tree (or the table is confirmed empty at seed time). While
+    /// `!built`, consultation MUST NOT short-circuit — a present row
+    /// would otherwise be mis-classified as absent.
+    built: bool,
+    /// Set when the one-shot build scan observes a row count exceeding
+    /// `QUOTIENT_FILTER_BUILD_ROW_CAP`. Once set, consultation stays
+    /// disabled for the remainder of this connection's lifetime for
+    /// this root page, to avoid paying the scan cost on every call.
+    too_large_to_build: bool,
+    /// Set on any mutation (insert / remove) made during an active
+    /// transaction. Cleared at explicit COMMIT. Used by the rollback
+    /// path to invalidate only the filters that were actually touched
+    /// by the rolled-back transaction (see
+    /// `Connection::invalidate_qfs_on_rollback`).
+    modified_in_txn: bool,
+}
+
+impl QuotientFilterEntry {
+    fn new() -> Self {
+        Self {
+            filter: QuotientFilter::with_defaults(),
+            built: false,
+            too_large_to_build: false,
+            modified_in_txn: false,
+        }
+    }
+}
