+    // ---------------------------------------------------------------
+    // IMPL-9a: QuotientFilter integration helpers.
+    //
+    // The filter short-circuits absent-rowid DELETE / UPDATE under the
+    // direct-simple fast path so we don't pay a B-tree descent to
+    // confirm "no such row". False-positives are tolerable (descent
+    // confirms absent); false-negatives are FATAL (would under-delete).
+    // We eliminate FNs by (a) only consulting once the filter is
+    // fully seeded against the live B-tree, and (b) invalidating on
+    // rollback and DDL so a filter that includes never-committed
+    // inserts can never say "present" to the caller.
+    //
+    // Wiring status: scaffolding-only. The helpers below compile clean
+    // and are covered by their own logic, but are not yet invoked from
+    // the direct-simple DELETE/UPDATE execution sites (added in T1.3 /
+    // IMPL-1 at `execute_prepared_direct_simple_{update,delete}`) or
+    // from the INSERT / rollback / DDL paths. Each helper carries
+    // `#[allow(dead_code)]` until the consumption wiring lands.
+    // ---------------------------------------------------------------
+
+    /// Populate a freshly-constructed `QuotientFilter` by scanning
+    /// every rowid in the table rooted at `cursor`. On success,
+    /// returns `Ok(true)` with the entry marked `built`. If the scan
+    /// exceeds `QUOTIENT_FILTER_BUILD_ROW_CAP`, returns `Ok(false)`
+    /// and the entry is marked `too_large_to_build`. Clears any
+    /// partial content before returning.
+    #[allow(dead_code)]
+    fn quotient_filter_seed_from_cursor<P: PageReader + PageWriter>(
+        entry: &mut QuotientFilterEntry,
+        execution_cx: &Cx,
+        cursor: &mut fsqlite_btree::BtCursor<P>,
+    ) -> Result<bool> {
+        entry.filter.clear();
+        let has_any = cursor.first(execution_cx)?;
+        if !has_any {
+            // Empty table — filter is trivially seeded.
+            entry.built = true;
+            entry.too_large_to_build = false;
+            return Ok(true);
+        }
+        let mut seen: usize = 0;
+        loop {
+            let rowid = cursor.rowid(execution_cx)?;
+            // `insert` only fails past 4x capacity; at that point, the
+            // FP rate has degraded past usefulness. Treat it like the
+            // row-cap case: disable short-circuiting for this table.
+            if entry.filter.insert(quotient_filter_hash_rowid(rowid)).is_err() {
+                entry.filter.clear();
+                entry.built = false;
+                entry.too_large_to_build = true;
+                return Ok(false);
+            }
+            seen = seen.saturating_add(1);
+            if seen > QUOTIENT_FILTER_BUILD_ROW_CAP {
+                entry.filter.clear();
+                entry.built = false;
+                entry.too_large_to_build = true;
+                return Ok(false);
+            }
+            if !cursor.next(execution_cx)? {
+                break;
+            }
+        }
+        entry.built = true;
+        entry.too_large_to_build = false;
+        Ok(true)
+    }
+
+    /// Consult the per-table filter for an absent-rowid short-circuit
+    /// opportunity. If the filter for `root_page` has not yet been
+    /// built, this triggers a one-shot scan of the entire table via
+    /// `cursor`. Returns `Ok(true)` iff consultation proved the rowid
+    /// is absent (caller may short-circuit with 0 rows affected).
+    ///
+    /// If the filter is unusable (too-large-to-build, or build
+    /// failure), returns `Ok(false)` — safe default, caller descends
+    /// the B-tree normally.
+    #[allow(dead_code)]
+    fn qf_maybe_short_circuit_for_rowid<P: PageReader + PageWriter>(
+        &self,
+        execution_cx: &Cx,
+        root_page: i32,
+        rowid: i64,
+        cursor: &mut fsqlite_btree::BtCursor<P>,
+    ) -> Result<bool> {
+        let mut filters = self.quotient_filters.borrow_mut();
+        let entry = filters
+            .entry(root_page)
+            .or_insert_with(QuotientFilterEntry::new);
+        if entry.too_large_to_build {
+            return Ok(false);
+        }
+        if !entry.built {
+            // Build on first consultation. The scan uses `cursor`
+            // itself (the very cursor the DML path is about to use),
+            // so we re-seed it afterwards via the DML's own seek.
+            Self::quotient_filter_seed_from_cursor(entry, execution_cx, cursor)?;
+        }
+        if !entry.built {
+            // Build declined (too large or capacity overflow). Do not
+            // short-circuit.
+            return Ok(false);
+        }
+        let hash = quotient_filter_hash_rowid(rowid);
+        if entry.filter.contains(hash) {
+            // "Maybe present" — caller must descend to confirm.
+            Ok(false)
+        } else {
+            // "Definitely absent" — safe to short-circuit.
+            self.quotient_filter_short_circuits
+                .set(self.quotient_filter_short_circuits.get().saturating_add(1));
+            Ok(true)
+        }
+    }
+
+    /// Record a successful INSERT of `rowid` into the table rooted at
+    /// `root_page`. No-op if the filter entry does not yet exist; the
+    /// entry will be created and seeded at first consultation. If the
+    /// entry already exists and is built, this keeps it current so the
+    /// NEXT consultation sees the new row.
+    #[allow(dead_code)]
+    fn qf_record_insert(&self, root_page: i32, rowid: i64) {
+        let mut filters = self.quotient_filters.borrow_mut();
+        if let Some(entry) = filters.get_mut(&root_page) {
+            if entry.built {
+                // Ignore Err(()): capacity exhaustion just means the
+                // filter is no longer a reliable accelerator; the
+                // next consultation will still descend the B-tree
+                // normally if contains() answers "maybe".
+                let _ = entry
+                    .filter
+                    .insert(quotient_filter_hash_rowid(rowid));
+            }
+            if self.in_transaction.get() {
+                entry.modified_in_txn = true;
+            }
+        }
+    }
+
+    /// Record a successful DELETE of `rowid` from the table rooted at
+    /// `root_page`. If the entry is built, removes the corresponding
+    /// hash fingerprint; otherwise a no-op (the next consultation
+    /// seeds from the live B-tree, which already reflects the delete).
+    #[allow(dead_code)]
+    fn qf_record_delete(&self, root_page: i32, rowid: i64) {
+        let mut filters = self.quotient_filters.borrow_mut();
+        if let Some(entry) = filters.get_mut(&root_page) {
+            if entry.built {
+                entry.filter.remove(quotient_filter_hash_rowid(rowid));
+            }
+            if self.in_transaction.get() {
+                entry.modified_in_txn = true;
+            }
+        }
+    }
+
+    /// Invalidate all filters that were mutated during the current
+    /// (about-to-be-rolled-back) transaction. Each such filter is
+    /// reset to the unbuilt state; the next consultation will seed
+    /// from the committed B-tree.
+    #[allow(dead_code)]
+    fn invalidate_qfs_on_rollback(&self) {
+        let mut filters = self.quotient_filters.borrow_mut();
+        for entry in filters.values_mut() {
+            if entry.modified_in_txn {
+                entry.filter.clear();
+                entry.built = false;
+                entry.too_large_to_build = false;
+                entry.modified_in_txn = false;
+            }
+        }
+    }
+
+    /// Clear the per-transaction `modified_in_txn` flag on every
+    /// filter. Called on successful COMMIT so subsequent rollbacks in
+    /// later transactions do not wrongly invalidate filters whose
+    /// writes were durably committed.
+    #[allow(dead_code)]
+    fn clear_qf_txn_modifications(&self) {
+        let mut filters = self.quotient_filters.borrow_mut();
+        for entry in filters.values_mut() {
+            entry.modified_in_txn = false;
+        }
+    }
+
+    /// Drop the filter entry for a table whose root page is being
+    /// freed (DROP TABLE) or whose schema is otherwise being
+    /// invalidated (ALTER TABLE, schema reload). Subsequent lookups
+    /// will re-seed from the live B-tree if the root is re-used.
+    #[allow(dead_code)]
+    fn qf_invalidate_root(&self, root_page: i32) {
+        self.quotient_filters.borrow_mut().remove(&root_page);
+    }
+
+    /// Observability hook: number of times the QF has produced an
+    /// absent-rowid short-circuit on this connection.
+    #[cfg(test)]
+    #[must_use]
+    pub(crate) fn quotient_filter_short_circuit_count(&self) -> u64 {
+        self.quotient_filter_short_circuits.get()
+    }
+
+    #[cfg(test)]
+    pub(crate) fn reset_quotient_filter_short_circuit_count(&self) {
+        self.quotient_filter_short_circuits.set(0);
+    }
+
     fn eval_prepared_direct_simple_insert_explicit_rowid_only(
         &self,
         direct: &PreparedDirectSimpleInsert,
